#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long N,M; scanf("%lld %lld",&N,&M);
        long long sum=0, x;
        for(int i=0;i<M;i++){
            scanf("%lld",&x);
            sum+=x;
        }
        long long capacity = N*(M-1);
        long long ans = sum - capacity;
        if(ans<0) ans=0;
        printf("%lld\n", ans);
    }
    return 0;
}

