#!/usr/bin/env python3
import sys
def main():
    data = sys.stdin.read().strip().split()
    if not data: 
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        s = 0
        for _ in range(M):
            s += int(next(it))
        ans = s - N * (M - 1)
        if ans < 0:
            ans = 0
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    main()

